document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("csie-menu-toggle"),t=document.getElementById("csie-mobile-menu"),n=document.getElementById("csie-menu-label");e&&t&&e.addEventListener("click",()=>{const d=!t.classList.contains("hidden");t.classList.toggle("hidden"),e.setAttribute("aria-expanded",String(!d)),n&&(n.textContent=d?"menu":"close")})});
